def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity == 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio > 1:
            score += (ratio - 1) * 10
        elif ratio == 1:
            score += 5
        else:
            score += (1 - ratio) * 5
        remainder = capacity - item
        if remainder < 0:
            score += 100
        else:
            for j in range(1, int(remainder)+1):
                if remainder % j == 0:
                    score -= 0.1 * j
        priorities[i] = score
    max_val = np.max(priorities[np.isfinite(priorities)])
    priorities[np.isinf(priorities)] = max_val + 100
    return priorities
